        <nav className="flex flex-col h-full p-6">
          <NavigationLinks 
            locale={locale} 
            className="flex flex-col space-y-4" 
            itemClassName="text-lg py-2"
            onClick={() => setIsOpen(false)}
          />
        </nav>
      </SheetContent>
    </Sheet>
  );
}
