}

export function RoomAvailability({ roomId }: RoomAvailabilityProps) {
  const { locale } = useParams();
  const t = createTranslator(locale as string);

  const [date, setDate] = useState<Date | undefined>(new Date());

  // Mock time slots - in a real app, these would come from an API based on the selected date
  const timeSlots = [
    { start: '09:00', end: '10:00', isAvailable: true },
    { start: '10:00', end: '11:00', isAvailable: true },
    { start: '11:00', end: '12:00', isAvailable: false },
    { start: '12:00', end: '13:00', isAvailable: false },
    { start: '13:00', end: '14:00', isAvailable: true },
    { start: '14:00', end: '15:00', isAvailable: true },
    { start: '15:00', end: '16:00', isAvailable: true },
    { start: '16:00', end: '17:00', isAvailable: false },
    { start: '17:00', end: '18:00', isAvailable: true },
  ];

  return (
    <div>
      <h3 className="text-xl font-semibold mb-4">{t('check_availability')}</h3>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div>
          <Calendar
            mode="single"
            selected={date}
            onSelect={setDate}
            className="rounded-md border"
          />
        </div>

        <div>
          <h4 className="font-medium mb-4">
            {date ? format(date, 'EEEE, MMMM d, yyyy') : t('select_date')}
          </h4>

          {date && (
            <div className="space-y-2">
              {timeSlots.map((slot, index) => (
                <div 
                  key={index}
                  className={`p-3 rounded-md border flex justify-between items-center ${
                    slot.isAvailable ? 'bg-card' : 'bg-muted text-muted-foreground'
                  }`}
                >
                  <span>
                    {slot.start} - {slot.end}
                  </span>
                  {slot.isAvailable ? (
                    <Button size="sm" asChild>
                      <a href={`/reservation?room=${roomId}&date=${format(date, 'yyyy-MM-dd')}&time=${slot.start}`}>
                        {t('book')}
                      </a>
                    </Button>
                  ) : (
                    <span className="text-sm font-medium">{t('unavailable')}</span>
                  )}
                </div>
              ))}
            </div>
          )}
